import 'dart:convert';
import 'dart:typed_data';
import 'package:prizo/shared/data_entities/models/producto.dart';

class ProductoService {
  final String CESTA = "";
  final String PAPELERA = "";
  final String CASA = "";
  final String LUPA = "";
  final String LISTA = "";
  final String PERSONA = "";
  final String CASA_AZUL = "";
  final String LUPA_AZUL = "";
  final String LISTA_AZUL = "";
  final String PERSONA_AZUL = "";
  final String NOTIFICACIONES = "";
  final String SEGURIDAD = "";
  final String AYUDA = "";
  final String CERRAR_SESION = "";

  Uint8List getCesta() { return base64.decode((CESTA).split(',').last); }
  Uint8List getPapelera() { return base64.decode((CESTA).split(',').last); }
  Uint8List getCasa() { return base64.decode((CASA).split(',').last); }
  Uint8List getLupa() { return base64.decode((LUPA).split(',').last); }
  Uint8List getLista() { return base64.decode((LISTA).split(',').last); }
  Uint8List getPersona() { return base64.decode((PERSONA).split(',').last); }
  Uint8List getCasaAzul() { return base64.decode((CASA_AZUL).split(',').last); }
  Uint8List getLupaAzul() { return base64.decode((LUPA_AZUL).split(',').last); }
  Uint8List getListaAzul() { return base64.decode((LISTA_AZUL).split(',').last); }
  Uint8List getPersonaAzul() { return base64.decode((PERSONA_AZUL).split(',').last); }
  Uint8List getNotificaciones() { return base64.decode((NOTIFICACIONES).split(',').last); }
  Uint8List getSeguridad() { return base64.decode((SEGURIDAD).split(',').last); }
  Uint8List getAyuda() { return base64.decode((AYUDA).split(',').last); }
  Uint8List getCerrarSesion() { return base64.decode((CERRAR_SESION).split(',').last); }

  double getPrecio(Producto product) {
    if(product.oferta) {
      return product.precioOferta;
    }
    return product.precio;
  }

  bool mismoProducto(Producto productA, Producto productB) {
    /* Solo comparo los atributos que nunca cambian */
    return        productA.id == productB.id &&
        productA.nombre == productB.nombre &&
        productA.alergenos == productB.alergenos &&
        productA.tienda == productB.tienda &&
        productA.marca == productB.marca;
  }

  bool actualizadoProducto(Producto productA, Producto productB) {
    return      productA.foto != productB.foto ||
        productA.precio != productB.precio ||
        productA.precioMedida != productB.precioMedida ||
        productA.oferta != productB.oferta ||
        productA.precioOferta != productB.precioOferta;
  }

  String generarClave(Producto producto) {
    return '${producto.id}_${producto.nombre}_${producto.tienda}_${producto.marca}';
  }

  /**
   * Consistirá en una lista de 3 booleanos con las posiciones establecidas de la siguiente manera
   * - Posición 0: booleano para el GLUTEN
   * - Posición 1: booleano para la LACTOSA
   * - Posición 2: booleano para los FRUTOS SECOS
   * */
  bool tieneAlergeno(Producto producto, int indice) {
    if (indice < 0 || indice >= producto.alergenos.length) {
      throw ArgumentError("Índice fuera de rango");
    }
    return producto.alergenos[indice];
  }
}